import { Rewrite } from '@rewritejs/sdk';

const rewrite = new Rewrite(process.env.REWRITE_API_KEY);

const { data, error } = await rewrite.messages.send({
  to: '+5511999999999',
  content: 'Rewrite: seu codigo e 478201',
  tags: [{ name: 'flow', value: 'login' }],
});

if (error) throw error;

import { Rewrite } from '@rewritejs/sdk';

const rewrite = new Rewrite(process.env.REWRITE_API_KEY);

const { data, error, cursor } = await rewrite.messages.list({
  limit: 25,
  status: 'DELIVERED',
});

if (error) throw error;

import { Rewrite } from '@rewritejs/sdk';

const rewrite = new Rewrite(process.env.REWRITE_API_KEY);

const { data, error } = await rewrite.messages.sendBatch([
  {
    to: '+5511999999999',
    content: 'Rewrite: seu codigo e 478201',
  },
  {
    to: '+5511888888888',
    templateId: '748395130237498620',
    variables: { code: '941205' },
  },
]);

if (error) throw error;

import { Rewrite } from '@rewritejs/sdk';

const rewrite = new Rewrite(process.env.REWRITE_API_KEY);

const { error } = await rewrite.messages.cancel({
  id: '748395130237498412',
});

if (error) throw error;

